+package topk
+
+import "testing"
+
+// TestEvictionPicksFirstMinimum checks that when the tracked set is full
+// and incoming counts tie with existing entries, the first slot that
+// reaches the minimum is evicted (not a later tied slot).
+func TestEvictionPicksFirstMinimum(t *testing.T) {
+	tk := New(2)
+	tk.Observe("a")
+	tk.Observe("b")
+	tk.Observe("c")
+
+	keys := map[string]bool{}
+	for _, c := range tk.Snapshot() {
+		keys[c.Key] = true
+	}
+	if keys["a"] {
+		t.Fatalf("expected first-min 'a' to be evicted, got %v", keys)
+	}
+	if !keys["b"] {
+		t.Fatalf("expected 'b' to be retained, got %v", keys)
+	}
+}
+
+// TestNonFullUnaffected confirms the non-full insertion path is unchanged.
+func TestNonFullUnaffected(t *testing.T) {
+	tk := New(3)
+	tk.Observe("a")
+	tk.Observe("a")
+	tk.Observe("b")
+	if tk.Snapshot()[0].Key != "a" {
+		t.Fatalf("expected 'a' on top, got %v", tk.Snapshot())
+	}
+}

